// 模範解答: 右手法(右手を壁につけたまま歩く)。
// どんな迷路・地形でも、外周とつながった壁沿いを
// たどっていけば必ずゴールにたどりつく。
int main(void) {
    while (!is_goal()) {
        turn_right();                      // まず右を向いてみる
        if (is_wall_ahead()) turn_left();  // 壁ならすこしずつ左へ戻す
        if (is_wall_ahead()) turn_left();
        if (is_wall_ahead()) turn_left();
        move_forward();                    // あいている方向へ1マス進む
    }
    return 0;
}

#include <stdio.h>

int main(void) {
    int h, w;
    scanf("%d %d", &h, &w);
    int sums[20];
    for (int i = 0; i < h; i++) {
        int sum = 0;
        for (int j = 0; j < w; j++) {
            int v;
            scanf("%d", &v);
            sum += v;
        }
        sums[i] = sum;
        printf("%d\n", sum);
    }
    int best = 0;
    for (int i = 1; i < h; i++) if (sums[i] > sums[best]) best = i;
    printf("%d\n", best + 1);
    return 0;
}

