#include "game.h"

// 模範解答: 選択ソート。
// i 番目に「まだ並べていない中でいちばん小さい値」を置いていく。
// 交換回数が少ないので星も取りやすい。
int main(void) {
    int n = array_length();
    for (int i = 0; i < n - 1; i++) {
        int minIdx = i;
        for (int j = i + 1; j < n; j++) {
            if (get_value(j) < get_value(minIdx)) minIdx = j;
        }
        if (minIdx != i) swap_values(i, minIdx);
    }
    return 0;
}

