#include "game.h"

// 模範解答: 最大値の場所を探して、最後の位置と1回だけ交換する。
int main(void) {
    int n = array_length();
    int maxIdx = 0;
    for (int i = 1; i < n; i++) {
        if (get_value(i) > get_value(maxIdx)) maxIdx = i;
    }
    if (maxIdx != n - 1) swap_values(maxIdx, n - 1);
    return 0;
}

