#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);
    int a[100];
    for (int i = 0; i < n; i++) scanf("%d", &a[i]);
    int bestValue = a[0], bestCount = 0;
    for (int i = 0; i < n; i++) {
        int cnt = 0;
        for (int j = 0; j < n; j++) if (a[j] == a[i]) cnt++;
        if (cnt > bestCount || (cnt == bestCount && a[i] < bestValue)) {
            bestCount = cnt;
            bestValue = a[i];
        }
    }
    printf("%d\n", bestValue);
    return 0;
}

